package com.ruoyi.modules.invest.benefit.indicator.service.impl;
import com.ruoyi.common.utils.DateUtils;import com.ruoyi.common.utils.ShiroUtils;import com.ruoyi.modules.invest.benefit.indicator.domain.InvestBenefitIndicator;import com.ruoyi.modules.invest.benefit.indicator.mapper.InvestBenefitIndicatorMapper;import com.ruoyi.modules.invest.benefit.indicator.service.IInvestBenefitIndicatorService;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.stereotype.Service;import java.util.List;@Service public class InvestBenefitIndicatorServiceImpl implements IInvestBenefitIndicatorService{@Autowired private InvestBenefitIndicatorMapper mapper;public InvestBenefitIndicator selectById(Long id){return mapper.selectById(id);}public List<InvestBenefitIndicator> selectList(InvestBenefitIndicator i){return mapper.selectList(i);}public int insert(InvestBenefitIndicator i){i.setCreateBy(ShiroUtils.getLoginName());i.setCreateTime(DateUtils.getNowDate());i.setDelFlag("0");if(i.getStatus()==null)i.setStatus("0");return mapper.insert(i);}public int update(InvestBenefitIndicator i){i.setUpdateBy(ShiroUtils.getLoginName());i.setUpdateTime(DateUtils.getNowDate());return mapper.update(i);}public int deleteByIds(Long[] ids){return mapper.deleteByIds(ids);}}